import React from 'react';
import { ContextMenu as CarbonContextMenu } from '@carbon/react';

const ContextMenu = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonContextMenu
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonContextMenu>
    );
};

ContextMenu.defaultProps = {
    className: ''
};

export default ContextMenu;
